proof fn phi_3_singleton_map_values_to_set(v: int, map: spec_fn(int) -> int)
    ensures
        seq![v].map_values(map).to_set() == Set::empty().insert(map(v)),
{
    map_values_to_set_eq_to_set_mk_map_values(seq![v], map);
}

proof fn phi_4_map_values_to_set_len_leq_seq_len(s: Seq<int>, map: spec_fn(int) -> int)
    requires
        s.to_set().finite(),
    ensures
        s.map_values(map).to_set().len() <= s.to_set().len(),
{
    map_values_to_set_eq_to_set_mk_map_values(s, map);
}

